let appUrl = 'https://geo.pkbmtunasilmu.web.id';
const n8nApiKey = 'ISI_N8N_API_KEY_APLIKASI_DI_SINI';
let gowaUrl = 'ISI_URL_GOWA_DI_SINI';
const forceRun = false; // Ubah sementara ke true untuk tes manual di luar tanggal terakhir bulan.

while (appUrl.endsWith('/')) appUrl = appUrl.slice(0, -1);
if (appUrl.toLowerCase().endsWith('/api')) appUrl = appUrl.slice(0, -4);
gowaUrl = String(gowaUrl).trim();

if (!n8nApiKey || n8nApiKey === 'ISI_N8N_API_KEY_APLIKASI_DI_SINI') {
  throw new Error('Isi n8nApiKey di node Konfigurasi & Cek Akhir Bulan dengan nilai N8N_API_KEY aplikasi presensi.');
}
if (!gowaUrl || gowaUrl === 'ISI_URL_GOWA_DI_SINI') {
  throw new Error('Isi gowaUrl di node Konfigurasi & Cek Akhir Bulan dengan URL endpoint Gowa.');
}

const now = new Date();
const parts = Object.fromEntries(new Intl.DateTimeFormat('en-CA', { timeZone: 'Asia/Jakarta', year: 'numeric', month: '2-digit', day: '2-digit' }).formatToParts(now).map((part) => [part.type, part.value]));
const year = Number(parts.year);
const month = Number(parts.month);
const day = Number(parts.day);
const lastDay = new Date(year, month, 0).getDate();

if (!forceRun && day !== lastDay) {
  return [];
}

const pad = (value) => String(value).padStart(2, '0');
const startDate = `${year}-${pad(month)}-01`;
const endDate = `${year}-${pad(month)}-${pad(lastDay)}`;
const monthLabel = new Intl.DateTimeFormat('id-ID', { timeZone: 'Asia/Jakarta', month: 'long', year: 'numeric' }).format(new Date(Date.UTC(year, month - 1, 1)));

return [{ json: { appUrl, n8nApiKey, gowaUrl, timezone: 'Asia/Jakarta', year, month, day, lastDay, startDate, endDate, monthLabel, forceRun, generatedAt: now.toISOString() } }];

const cfg = $items('Konfigurasi & Cek Akhir Bulan')[0].json;
const pad = (value) => String(value).padStart(2, '0');
const dates = [];
for (let day = 1; day <= cfg.lastDay; day++) {
  dates.push({ json: { ...cfg, tanggal: `${cfg.year}-${pad(cfg.month)}-${pad(day)}`, dayOfMonth: day } });
}
return dates;

const cfg = $items('Konfigurasi & Cek Akhir Bulan')[0].json;
const guruResponse = $items('Ambil Data Guru')[0].json;
if (!guruResponse.success || !Array.isArray(guruResponse.data)) {
  throw new Error('Response guru dari API tidak valid.');
}
const gurus = guruResponse.data;
const holidayItems = $items('Cek Hari Kerja Per Tanggal').map((item) => item.json.data || item.json);
let workdays = holidayItems.filter((dateInfo) => dateInfo && dateInfo.isWorkday).map((dateInfo) => dateInfo.tanggal).sort();
const pad = (value) => String(value).padStart(2, '0');
if (workdays.length === 0) {
  workdays = Array.from({ length: cfg.lastDay }, (_, index) => `${cfg.year}-${pad(cfg.month)}-${pad(index + 1)}`);
}
const presensiResponses = $input.all().map((item) => item.json);
const logs = presensiResponses.flatMap((response) => Array.isArray(response.data) ? response.data : []);
const logsByUser = new Map();
for (const log of logs) {
  const userKey = String(log.userId || log.user_id || '');
  if (!userKey) continue;
  if (!logsByUser.has(userKey)) logsByUser.set(userKey, []);
  logsByUser.get(userKey).push(log);
}
const statusLabel = (status) => ({
  hadir: 'Hadir',
  hadir_terlambat: 'Hadir terlambat',
  hadir_izin_terlambat: 'Izin terlambat',
  izin: 'Izin',
  sakit: 'Sakit'
}[status] || status || '-');
const normalizePhone = (raw) => {
  let phone = String(raw || '').trim().replace(/[^0-9+]/g, '');
  if (phone.startsWith('+')) phone = phone.slice(1);
  if (phone.startsWith('0')) phone = `62${phone.slice(1)}`;
  if (phone.startsWith('8')) phone = `62${phone}`;
  return phone;
};
const formatDate = (date) => `${date.slice(8, 10)}/${date.slice(5, 7)}`;
const gowaUrl = String(cfg.gowaUrl || '').trim();
if (!gowaUrl) {
  throw new Error('Isi gowaUrl di node Konfigurasi & Cek Akhir Bulan.');
}
const output = [];
for (const guru of gurus) {
  const phone = normalizePhone(guru.noHP || guru.no_hp || '');
  if (!phone) continue;
  const userLogs = (logsByUser.get(String(guru.id)) || []).sort((a, b) => String(a.tanggal).localeCompare(String(b.tanggal)));
  const logsByDate = new Map(userLogs.map((log) => [log.tanggal, log]));
  const counts = { hadir: 0, terlambat: 0, izinTerlambat: 0, izin: 0, sakit: 0, lainnya: 0 };
  for (const log of userLogs) {
    if (log.status === 'hadir') counts.hadir++;
    else if (log.status === 'hadir_terlambat') counts.terlambat++;
    else if (log.status === 'hadir_izin_terlambat') counts.izinTerlambat++;
    else if (log.status === 'izin') counts.izin++;
    else if (log.status === 'sakit') counts.sakit++;
    else counts.lainnya++;
  }
  const hadirTotal = counts.hadir + counts.terlambat + counts.izinTerlambat;
  const absentDates = workdays.filter((date) => !logsByDate.has(date));
  const percentage = workdays.length > 0 ? ((hadirTotal / workdays.length) * 100).toFixed(1) : '0.0';
  const details = workdays.map((date, index) => {
    const log = logsByDate.get(date);
    if (!log) return `${index + 1}. ${formatDate(date)} - Tidak presensi`;
    const masuk = log.jamMasuk || log.jam_masuk || log.jamHadir || log.jam_hadir || '-';
    const pulang = log.jamPulang || log.jam_pulang || '-';
    const ket = log.keterangan ? ` (${String(log.keterangan).trim()})` : '';
    if (log.status === 'izin') return `${index + 1}. ${formatDate(date)} - Izin${ket}`;
    if (log.status === 'sakit') return `${index + 1}. ${formatDate(date)} - Sakit${ket}`;
    return `${index + 1}. ${formatDate(date)} - ${statusLabel(log.status)} ${masuk} / ${pulang}${ket}`;
  }).join('\n');
  const message = [
    '*Rekap Presensi Bulanan*',
    '',
    `Assalamu'alaikum Bapak/Ibu *${guru.nama}*,`,
    '',
    `Berikut rekap presensi periode *${cfg.monthLabel}* (${cfg.startDate} s.d. ${cfg.endDate}).`,
    '',
    `Total hari kerja: *${workdays.length}*`,
    `Hadir tepat waktu: *${counts.hadir}*`,
    `Hadir terlambat: *${counts.terlambat}*`,
    `Izin terlambat: *${counts.izinTerlambat}*`,
    `Izin: *${counts.izin}*`,
    `Sakit: *${counts.sakit}*`,
    `Tidak presensi: *${absentDates.length}*`,
    `Persentase hadir: *${percentage}%*`,
    '',
    '*Detail hari kerja:*',
    details || '-',
    '',
    'Catatan: Hari libur dan akhir pekan tidak dihitung sebagai tidak presensi.',
    '',
    '_Sistem GeoPresensi Griya Quran_'
  ].join('\n');
  output.push({ json: { nama: guru.nama, userId: guru.id, phone, message, gowaUrl, monthLabel: cfg.monthLabel, startDate: cfg.startDate, endDate: cfg.endDate, totalHariKerja: workdays.length, hadir: hadirTotal, izin: counts.izin, sakit: counts.sakit, tidakPresensi: absentDates.length, persentaseHadir: percentage } });
}
if (output.length === 0) {
  throw new Error('Tidak ada guru dengan nomor WhatsApp/no_hp yang valid.');
}
return output;
